"use client"

/*
 * ======================================================================================
 * PERMANENT REGRESSION GUARD: QUANTITY ISOLATION RULES
 * ======================================================================================
 * Context: Owner Menu Planner (Edit Mode)
 * Critical Requirement: Each selected dish MUST maintain independent quantity state.
 * 
 * NON-NEGOTIABLE RULES:
 * 1. Every UI item must have a `uiId` (frontend-only unique string).
 *    - Generated on `fetchExistingMenu` and `toggleDishSelection`.
 * 2. React list `key` prop MUST use `item.uiId`.
 *    - NEVER use array index.
 *    - NEVER use backend `_id` (duplicates exist in menu editing).
 * 3. Quantity updates (`updateMaxQuantity`) MUST target `uiId` strictly.
 * 4. State updates MUST be immutable (map by `uiId`).
 * 5. `uiId` MUST be stripped before API save (`handlePublishMenu`).
 * 6. Shared object references are FORBIDDEN. Always clone items on load.
 * 
 * FAILURE TO FOLLOW THESE RULES WILL CAUSE "UPDATE ALL" BUGS.
 * ======================================================================================
 */

import { useState, useEffect, useCallback } from 'react'
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Plus, Minus, Search, Check, Calendar as CalendarIcon, RefreshCw, AlertCircle } from "lucide-react"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Badge } from "@/components/ui/badge"
import { Tabs, TabsList, TabsTrigger } from "@/components/ui/tabs"
import { toast } from "sonner"
import axios from "axios"
import { API_URL } from "@/lib/config"

interface FoodItem {
    _id: string
    uiId?: string // Frontend-only unique ID for state isolation
    foodName: string
    imageUrl: string
    category: string
    vegOrNonVeg: 'veg' | 'non-veg'
    price: number
    isCustomDish?: boolean
    maxQuantity?: number // Current Max Limit set by Owner
}

const CATEGORIES = ["All", "Main", "Breads", "Rice", "Beverages", "Dessert", "Snacks"]
const LIMIT = 20

export default function MenuPage() {
    // Selection State
    const [selectedDate, setSelectedDate] = useState('')
    const [selectedMealType, setSelectedMealType] = useState<'breakfast' | 'lunch' | 'dinner'>('breakfast')
    // CHANGED: Store full objects to persist selection across searches/filters
    const [selectedDishes, setSelectedDishes] = useState<FoodItem[]>([])
    const [maxDishesPerStudent, setMaxDishesPerStudent] = useState<string>('') // Empty string = no limit

    // Catalog & Filter State
    const [catalog, setCatalog] = useState<FoodItem[]>([])
    const [loading, setLoading] = useState(true)
    const [loadingMore, setLoadingMore] = useState(false)
    const [error, setError] = useState(false)

    const [page, setPage] = useState(1)
    const [hasMore, setHasMore] = useState(true)

    const [searchQuery, setSearchQuery] = useState('')
    const [filterCategory, setFilterCategory] = useState('All')
    const [filterVegType, setFilterVegType] = useState<'all' | 'veg' | 'non-veg'>('all')

    // Custom Dish Form State
    const [customForm, setCustomForm] = useState({
        foodName: '',
        category: 'Main',
        vegOrNonVeg: 'veg' as 'veg' | 'non-veg',
        price: '0',
        image: null as File | null
    })
    const [uploading, setUploading] = useState(false)
    const [retryCount, setRetryCount] = useState(0)

    // Server-Side Search Effect
    useEffect(() => {
        // Initial Cache Check
        const cached = sessionStorage.getItem('dishCache')
        if (cached) {
            try {
                const { data, timestamp } = JSON.parse(cached)
                if (Date.now() - timestamp < 60000) { // 1 min frontend cache
                    setCatalog(data)
                    setLoading(false)
                    setPage(2)
                }
            } catch (e) {
                sessionStorage.removeItem('dishCache')
            }
        }

        const delayDebounceFn = setTimeout(() => {
            fetchDishes(true)
        }, 300)


        return () => clearTimeout(delayDebounceFn)
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [searchQuery, filterCategory, filterVegType])

    const fetchDishes = async (reset = false) => {
        if (reset) {
            setLoading(true)
            setError(false)
            setHasMore(true)
        } else {
            setLoadingMore(true)
        }

        try {
            // Cookie based auth - no local check needed

            const params = new URLSearchParams()
            if (searchQuery) params.append('search', searchQuery)
            if (filterCategory !== 'All') params.append('category', filterCategory)
            if (filterVegType !== 'all') params.append('vegType', filterVegType)

            const currentPage = reset ? 1 : page
            params.append('page', currentPage.toString())
            params.append('limit', LIMIT.toString())

            const res = await axios.get(`${API_URL}/api/owner/dishes?${params.toString()}`, {
                withCredentials: true
            })

            const newItems: FoodItem[] = res.data.dishes || []

            if (reset) {
                setCatalog(newItems)
                setPage(2)
            } else {
                setCatalog(prev => {
                    const existingIds = new Set(prev.map(i => i._id))
                    const uniqueNew = newItems.filter(i => !existingIds.has(i._id))
                    return [...prev, ...uniqueNew]
                })
                setPage(prev => prev + 1)
            }

            if (newItems.length < LIMIT) {
                setHasMore(false)
            } else {
                setHasMore(true)
            }
            setError(false)
            setRetryCount(0)

            // Cache update only for default view
            if (reset && !searchQuery && filterCategory === 'All' && filterVegType === 'all') {
                sessionStorage.setItem('dishCache', JSON.stringify({
                    data: newItems,
                    timestamp: Date.now()
                }))
            }

        } catch (error: any) {
            console.error("Fetch dishes error:", error)

            if (error.response?.status === 401) {
                toast.error("Session expired")
                localStorage.removeItem('token')
                window.location.href = '/login'
                return
            }

            // AUTO RETRY LOGIC (1 attempt) - Skip for 4xx errors
            if (retryCount < 1 && (!error.response || error.response.status >= 500)) {
                console.log('Retrying fetch...')
                setRetryCount(prev => prev + 1)
                setTimeout(() => fetchDishes(reset), 1000)
                return;
            }

            setError(true)
            toast.error("Failed to load dishes")
        } finally {
            setLoading(false)
            setLoadingMore(false)
        }
    }

    // Logic for showing custom form:
    // If search is active (length > 0) AND server returns empty list -> Show Form
    const showCustomForm = !loading && catalog.length === 0 && searchQuery.length > 0 && !error;

    // CHANGED: Accepts full object now
    const toggleDishSelection = (dish: FoodItem) => {
        setSelectedDishes(prev => {
            const exists = prev.find(d => d._id === dish._id)
            if (exists) {
                return prev.filter(d => d._id !== dish._id)
            } else {
                // Initialize with maxQuantity = 1 & Unique UI ID
                // Inline generator for safety
                const newUiId = (typeof crypto !== 'undefined' && crypto.randomUUID)
                    ? crypto.randomUUID()
                    : `ui-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;

                return [...prev, { ...dish, uiId: newUiId, maxQuantity: 1 }]
            }
        })
    }

    const updateMaxQuantity = (id: string, delta: number) => {
        setSelectedDishes(prev => prev.map(item => {
            if (item.uiId === id) {
                const current = item.maxQuantity || 1;
                const next = Math.max(1, current + delta); // Min 1
                return { ...item, maxQuantity: next };
            }
            return item;
        }));
    };

    const handleCustomSubmit = async (e: React.FormEvent) => {
        e.preventDefault()
        if (!customForm.image) {
            toast.error("Image is mandatory for custom dishes")
            return
        }
        if (!customForm.foodName.trim()) {
            toast.error("Dish name is required")
            return
        }

        setUploading(true)
        try {
            const formData = new FormData()
            formData.append('foodName', customForm.foodName)
            formData.append('category', customForm.category)
            formData.append('vegOrNonVeg', customForm.vegOrNonVeg)
            formData.append('price', customForm.price)
            formData.append('image', customForm.image)

            const res = await axios.post(`${API_URL}/api/owner/add-custom-dish`, formData, {
                withCredentials: true,
                headers: {
                    'Content-Type': 'multipart/form-data'
                }
            })

            toast.success("Dish Created!")

            const newDish = res.data
            // Add to catalog 
            setCatalog(prev => [newDish, ...prev])
            // Select automatically with default maxQuantity
            setSelectedDishes(prev => [...prev, { ...newDish, maxQuantity: 1 }])

            // Reset
            setCustomForm({
                foodName: '',
                category: 'Main',
                vegOrNonVeg: 'veg',
                price: '0',
                image: null
            })
            setSearchQuery('')

        } catch (error: any) {
            console.error(error)
            toast.error(error.response?.data?.msg || "Failed to create dish")
        } finally {
            setUploading(false)
        }
    }

    // Editable Menu State
    const [isEditing, setIsEditing] = useState(false)
    const [menuLoading, setMenuLoading] = useState(false)
    const [lastUpdated, setLastUpdated] = useState<string | null>(null)

    // Check for existing menu when Date or MealType changes
    useEffect(() => {
        if (selectedDate && selectedMealType) {
            fetchExistingMenu()
        } else {
            // Reset if selection invalid/cleared
            setSelectedDishes([])
            setMaxDishesPerStudent('')
            setIsEditing(false)
        }
    }, [selectedDate, selectedMealType])

    // CHANGED: Added `silent` parameter to suppress toast on re-fetch
    const fetchExistingMenu = async (silent = false) => {
        if (!selectedDate || !selectedMealType) return

        setMenuLoading(true)
        try {
            const res = await axios.get(`${API_URL}/api/owner/menu`, {
                params: { date: selectedDate, mealType: selectedMealType },
                withCredentials: true
            })

            const menu = res.data
            // Combine items
            const existingItems: FoodItem[] = [
                ...(menu.vegItems || []),
                ...(menu.nonVegItems || [])
            ]

            // Transform to FoodItem format (ensure _id matches catalog)
            // Note: Menu items might have generated _ids if not linked properly. 
            // Ideally we need the original FoodItem _id. 
            // In our Schema, MenuItemSchema is embedded but likely contains the same fields.
            // If _id validation fails, we might need to rely on foodName or check if _id is preserved.
            // Assuming _id is preserved or we can use item properties.

            // Re-map to ensure maxQuantity is present AND IDs are unique
            const seenIds = new Set();

            // Helper for robust ID generation
            const generateUiId = () => {
                if (typeof crypto !== 'undefined' && crypto.randomUUID) {
                    return crypto.randomUUID();
                }
                return `ui-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
            }

            const mappedItems = existingItems.map((item: any, index: number) => {
                // Generate robust ID: Use existing if valid & unique, else generated
                let finalId = item._id;
                if (!finalId || seenIds.has(finalId)) {
                    finalId = `temp-${Date.now()}-${index}-${Math.random().toString(36).substr(2, 5)}`;
                }
                seenIds.add(finalId);

                return {
                    _id: finalId,
                    uiId: generateUiId(), // FIXED: Assign unique frontend ID
                    foodName: item.foodName,
                    imageUrl: item.imageUrl,
                    category: item.category,
                    vegOrNonVeg: item.vegOrNonVeg,
                    price: item.price,
                    isCustomDish: item.isCustomDish,
                    maxQuantity: item.maxQuantity || 1
                };
            })

            setSelectedDishes(mappedItems)
            setIsEditing(true)
            if (menu.updatedAt) setLastUpdated(menu.updatedAt)
            // Load configured limit or reset
            setMaxDishesPerStudent(menu.maxDishesPerStudent ? String(menu.maxDishesPerStudent) : '')
            // CHANGED: Only show toast if NOT silent
            if (!silent) {
                toast.info(`Loaded existing ${selectedMealType} menu for editing`)
            }

        } catch (error: any) {
            // 404 is expected for new menus
            if (error.response?.status === 404) {
                setSelectedDishes([])
                setIsEditing(false)
            } else {
                console.error("Error fetching existing menu:", error)
            }
        } finally {
            setMenuLoading(false)
        }
    }

    const handlePublishMenu = async (status: 'DRAFT' | 'PUBLISHED') => {
        if (!selectedDate) {
            toast.error("Please select a date")
            return
        }
        if (selectedDishes.length === 0) {
            toast.error("Please select at least one dish")
            return
        }

        try {
            // CHANGED: Use selectedDishes directly
            const selectedItems = selectedDishes

            // CHANGED: Strip _id AND uiId to ensure Mongoose generates fresh valid ObjectIds
            // This prevents "CastError" if we sent 'temp-...' IDs and avoids duplicate key errors
            const cleanItem = ({ _id, uiId, ...rest }: any) => rest;

            // Split into Veg and Non-Veg for new Schema
            const vegItems = selectedItems.filter(i => i.vegOrNonVeg === 'veg').map(cleanItem)
            const nonVegItems = selectedItems.filter(i => i.vegOrNonVeg === 'non-veg').map(cleanItem)

            const payload = {
                date: selectedDate,
                mealType: selectedMealType,
                vegItems,
                nonVegItems,
                status,
                maxDishesPerStudent: maxDishesPerStudent ? parseInt(maxDishesPerStudent) : null
            }

            await axios.post(`${API_URL}/api/owner/save-menu`, payload, {
                withCredentials: true
            })

            const action = status === 'DRAFT' ? 'saved as Draft' : 'published';
            toast.success(`Menu ${action} for ${selectedMealType}!`)

            // RESET LOGIC
            // Don't clear date/mealType, just refresh the data (which will start "editing" the just-saved menu)
            fetchExistingMenu(true) // CHANGED: Silent reload

            setSearchQuery('')
            setFilterCategory('All')
            setFilterVegType('all')

        } catch (error: any) {
            console.error(error)
            const errorMsg = error.response?.data?.msg || "Failed to update menu"
            toast.error(errorMsg)
        }
    }

    return (
        <div className="p-6 space-y-6">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-3xl font-extrabold tracking-tight text-foreground">Menu Planner</h1>
                    <p className="text-muted-foreground">Curate your daily menu for students.</p>
                </div>
                <div className="flex gap-2 items-center">
                    {isEditing && (
                        <div className="flex flex-col items-end mr-2">
                            <Badge variant="outline" className="border-amber-500 text-amber-600 bg-amber-50 mb-1">
                                Editing Mode
                            </Badge>
                            {lastUpdated && (
                                <span className="text-[10px] text-muted-foreground">
                                    Last Updated: {new Date(lastUpdated).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                </span>
                            )}
                        </div>
                    )}
                    <Button
                        variant="outline"
                        size="lg"
                        onClick={() => handlePublishMenu('DRAFT')}
                        className="border-gray-300 text-gray-700 hover:bg-gray-100"
                    >
                        Save Draft
                    </Button>
                    <Button
                        size="lg"
                        onClick={() => handlePublishMenu('PUBLISHED')}
                        className={`shadow-lg uppercase font-bold tracking-wide text-white transition-all
                            ${isEditing
                                ? 'bg-amber-600 hover:bg-amber-700 shadow-amber-500/20'
                                : 'bg-emerald-600 hover:bg-emerald-700 shadow-emerald-500/20'
                            }`}
                    >
                        <Check className="w-4 h-4 mr-2" />
                        {isEditing ? 'Update & Publish' : 'Publish Menu'}
                    </Button>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">

                {/* LEFT PANEL: Controls */}
                <Card className="lg:col-span-4 sticky top-6 border-0 shadow-md bg-white/80 backdrop-blur-sm self-start">
                    <CardHeader className="pb-4 border-b">
                        <CardTitle className="text-xl">Configuration</CardTitle>
                        <CardDescription>Select target date and meal type</CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-6 pt-6">
                        <div className="space-y-2">
                            <Label>Date</Label>
                            <div className="relative">
                                <CalendarIcon className="absolute left-3 top-2.5 h-4 w-4 text-muted-foreground" />
                                <Input
                                    type="date"
                                    className="pl-9"
                                    min={new Date().toLocaleDateString('en-CA')} // YYYY-MM-DD in local time
                                    value={selectedDate}
                                    onChange={e => {
                                        const val = e.target.value;
                                        const today = new Date().toLocaleDateString('en-CA');
                                        if (val && val < today) {
                                            toast.error("Past dates are not allowed");
                                            return;
                                        }
                                        setSelectedDate(val);
                                    }}
                                />
                            </div>
                        </div>

                        <div className="space-y-2">
                            <Label>Meal Type</Label>
                            <Tabs value={selectedMealType} onValueChange={(v: any) => setSelectedMealType(v)} className="w-full">
                                <TabsList className="grid grid-cols-3 w-full">
                                    <TabsTrigger value="breakfast">Breakfast</TabsTrigger>
                                    <TabsTrigger value="lunch">Lunch</TabsTrigger>
                                    <TabsTrigger value="dinner">Dinner</TabsTrigger>
                                </TabsList>
                            </Tabs>
                        </div>

                        {/* Max Dish Types Control */}
                        <div className="space-y-3 pt-2">
                            <div className="flex justify-between items-center">
                                <Label>Max Dish Types Allowed</Label>
                                <span className={`text-[10px] uppercase font-bold tracking-wider ${maxDishesPerStudent ? "text-primary" : "text-muted-foreground"}`}>
                                    {maxDishesPerStudent ? "Limit Set" : "Unlimited"}
                                </span>
                            </div>
                            <div className="flex items-center gap-3">
                                <div className="flex items-center border rounded-lg bg-white dark:bg-zinc-900 shadow-sm">
                                    <Button
                                        variant="ghost"
                                        size="icon"
                                        onClick={() => {
                                            const current = parseInt(maxDishesPerStudent || '0');
                                            if (current > 1) setMaxDishesPerStudent(String(current - 1));
                                            else setMaxDishesPerStudent('');
                                        }}
                                        className="h-10 w-10 text-lg hover:bg-gray-100 dark:hover:bg-zinc-800 rounded-l-lg"
                                        disabled={!maxDishesPerStudent}
                                    >
                                        <Minus className="w-4 h-4" />
                                    </Button>
                                    <div className="w-12 text-center font-bold text-lg tabular-nums border-x border-gray-100 dark:border-zinc-800 h-6 flex items-center justify-center">
                                        {maxDishesPerStudent || '∞'}
                                    </div>
                                    <Button
                                        variant="ghost"
                                        size="icon"
                                        onClick={() => {
                                            const current = parseInt(maxDishesPerStudent || '0');
                                            // Start at 1 if empty
                                            const next = current === 0 ? 1 : current + 1;
                                            setMaxDishesPerStudent(String(next));
                                        }}
                                        className="h-10 w-10 text-lg hover:bg-gray-100 dark:hover:bg-zinc-800 rounded-r-lg bg-primary/5 text-primary"
                                    >
                                        <Plus className="w-4 h-4" />
                                    </Button>
                                </div>
                                <p className="text-xs text-muted-foreground leading-tight flex-1">
                                    {maxDishesPerStudent
                                        ? `Students restricted to ${maxDishesPerStudent} unique dishes.`
                                        : "Students can select any number of varied dishes."}
                                </p>
                            </div>
                        </div>

                        {/* SELECTED DISHES LIST */}
                        <div className="pt-4 border-t space-y-3">
                            <div className="flex justify-between items-center text-sm font-medium">
                                <span>Selected Dishes:</span>
                                {/* CHANGED: length instead of size */}
                                <Badge variant="secondary" className="text-lg px-3 bg-primary/10 text-primary hover:bg-primary/20">{selectedDishes.length}</Badge>
                            </div>

                            {selectedDishes.length > 0 ? (
                                // CHANGED: max-h-[250px] as requested
                                <div className="space-y-2 max-h-[250px] overflow-y-auto pr-1 custom-scrollbar">
                                    {/* CHANGED: map selectedDishes directly */}
                                    {selectedDishes.map(item => (
                                        <div
                                            key={item.uiId} // CRITICAL: Use uiId for React Key
                                            className="group flex flex-col gap-2 p-3 rounded-lg border bg-card hover:bg-destructive/5 hover:border-destructive/20 transition-all relative shadow-sm"
                                        >
                                            <div className="flex items-center gap-3">
                                                <img src={item.imageUrl} alt={item.foodName} className="w-12 h-12 rounded-lg object-cover bg-muted ring-1 ring-border" />
                                                <div className="flex-1 min-w-0">
                                                    <p className="text-sm font-semibold truncate text-foreground">{item.foodName}</p>
                                                    <div className="flex items-center gap-2 mt-0.5">
                                                        <span className={`text-[10px] uppercase font-bold px-1.5 py-0.5 rounded ${item.vegOrNonVeg === 'veg' ? 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400' : 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400'}`}>
                                                            {item.vegOrNonVeg}
                                                        </span>
                                                    </div>
                                                </div>
                                                <Button
                                                    variant="ghost"
                                                    size="icon"
                                                    className="h-8 w-8 text-muted-foreground opacity-0 group-hover:opacity-100 group-hover:text-destructive hover:bg-destructive/10 transition-all absolute top-2 right-2"
                                                    onClick={(e) => {
                                                        e.stopPropagation();
                                                        toggleDishSelection(item);
                                                    }}
                                                >
                                                    <span className="sr-only">Remove</span>
                                                    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M18 6 6 18" /><path d="m6 6 12 12" /></svg>
                                                </Button>
                                            </div>

                                            {/* Quantity Controller */}
                                            <div className="text-xs flex items-center justify-between border-t pt-2 mt-1">
                                                <span className="text-muted-foreground font-medium">Max Limit:</span>
                                                <div className="flex items-center gap-2 bg-secondary/10 rounded-md p-0.5">
                                                    <Button
                                                        variant="ghost"
                                                        size="icon"
                                                        className="h-6 w-6 rounded-sm hover:bg-white shadow-sm"
                                                        onClick={(e) => {
                                                            e.stopPropagation();
                                                            if (item.uiId) updateMaxQuantity(item.uiId, -1);
                                                        }}
                                                    >
                                                        <span className="mb-0.5">-</span>
                                                    </Button>
                                                    <span className="w-4 text-center font-bold text-foreground">{item.maxQuantity || 1}</span>
                                                    <Button
                                                        variant="ghost"
                                                        size="icon"
                                                        className="h-6 w-6 rounded-sm hover:bg-white shadow-sm"
                                                        onClick={(e) => {
                                                            e.stopPropagation();
                                                            if (item.uiId) updateMaxQuantity(item.uiId, 1);
                                                        }}
                                                    >
                                                        <span className="mb-0.5">+</span>
                                                    </Button>
                                                </div>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            ) : (
                                <div className="flex flex-col items-center justify-center py-10 text-center border-2 border-dashed rounded-xl bg-gray-50/50 dark:bg-zinc-900/50">
                                    <div className="p-3 bg-white dark:bg-zinc-800 rounded-full mb-3 shadow-sm">
                                        <Plus className="w-5 h-5 text-muted-foreground" />
                                    </div>
                                    <p className="text-sm font-medium text-muted-foreground">No dishes selected</p>
                                    <p className="text-xs text-muted-foreground/70 mt-1">Select items from the list to add them.</p>
                                </div>
                            )}
                        </div>
                    </CardContent>
                </Card>

                {/* RIGHT PANEL: Dish Grid or Add Form */}
                <div className="lg:col-span-8 space-y-6">

                    {/* Search & Categories */}
                    <div className="space-y-4 bg-white dark:bg-zinc-900 p-4 rounded-xl shadow-sm border">
                        <div className="relative">
                            <Search className="absolute left-3 top-3 h-4 w-4 text-gray-400" />
                            <Input
                                placeholder="Search existing dishes..."
                                className="pl-9 bg-gray-50 border-0"
                                value={searchQuery}
                                onChange={e => setSearchQuery(e.target.value)}
                            />
                        </div>
                        <div className="flex gap-2 overflow-x-auto no-scrollbar pb-1">
                            {CATEGORIES.map(cat => (
                                <button
                                    key={cat}
                                    onClick={() => setFilterCategory(cat)}
                                    className={`px-4 py-1.5 rounded-full text-xs font-bold whitespace-nowrap transition-all border
                                        ${filterCategory === cat
                                            ? 'bg-gray-900 text-white border-gray-900'
                                            : 'bg-white text-gray-600 border-gray-200 hover:border-gray-400'
                                        }`}
                                >
                                    {cat}
                                </button>
                            ))}
                        </div>
                    </div>

                    {/* CONTENT AREA */}
                    {loading && catalog.length === 0 ? (
                        <div className="grid grid-cols-2 lg:grid-cols-3 gap-4">
                            {[1, 2, 3, 4, 5, 6].map(i => <div key={i} className="h-40 bg-gray-200 dark:bg-zinc-800 rounded-xl animate-pulse" />)}
                        </div>
                    ) : error ? (
                        <div className="flex flex-col items-center justify-center p-10 text-center">
                            <AlertCircle className="w-10 h-10 text-red-500 mb-2" />
                            <p className="text-muted-foreground mb-4">Network issue. Could not load dishes.</p>
                            <Button variant="outline" onClick={() => { setRetryCount(0); fetchDishes(true); }}>
                                <RefreshCw className="w-4 h-4 mr-2" /> Retry Now
                            </Button>
                        </div>
                    ) : showCustomForm ? (
                        <Card className="border-2 border-dashed border-primary/20 bg-primary/5">
                            <CardHeader>
                                <CardTitle>Add New Custom Dish</CardTitle>
                                <CardDescription>No results found for "{searchQuery}". Create a new dish.</CardDescription>
                            </CardHeader>
                            <CardContent>
                                <form onSubmit={handleCustomSubmit} className="space-y-4 max-w-lg">
                                    <div className="space-y-2">
                                        <Label>Dish Name</Label>
                                        <Input
                                            value={customForm.foodName || searchQuery}
                                            onChange={e => {
                                                setCustomForm({ ...customForm, foodName: e.target.value })
                                                if (searchQuery && e.target.value !== searchQuery) setSearchQuery(e.target.value)
                                            }}
                                            placeholder="e.g. Special Egg Dosa"
                                        />
                                    </div>
                                    <div className="grid grid-cols-2 gap-4">
                                        <div className="space-y-2">
                                            <Label>Category</Label>
                                            <Select value={customForm.category} onValueChange={v => setCustomForm({ ...customForm, category: v })}>
                                                <SelectTrigger><SelectValue /></SelectTrigger>
                                                <SelectContent>
                                                    {CATEGORIES.filter(c => c !== 'All').map(c => <SelectItem key={c} value={c}>{c}</SelectItem>)}
                                                </SelectContent>
                                            </Select>
                                        </div>
                                        <div className="space-y-2">
                                            <Label>Type</Label>
                                            <div className="flex gap-4 pt-2">
                                                <label className="flex items-center gap-2 cursor-pointer">
                                                    <input type="radio" name="veg" checked={customForm.vegOrNonVeg === 'veg'} onChange={() => setCustomForm({ ...customForm, vegOrNonVeg: 'veg' })} />
                                                    <span className="text-green-600 font-bold text-sm">Veg</span>
                                                </label>
                                                <label className="flex items-center gap-2 cursor-pointer">
                                                    <input type="radio" name="veg" checked={customForm.vegOrNonVeg === 'non-veg'} onChange={() => setCustomForm({ ...customForm, vegOrNonVeg: 'non-veg' })} />
                                                    <span className="text-red-600 font-bold text-sm">Non-Veg</span>
                                                </label>
                                            </div>
                                        </div>
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Image (Mandatory)</Label>
                                        <Input
                                            type="file"
                                            accept="image/*"
                                            onChange={e => setCustomForm({ ...customForm, image: e.target.files?.[0] || null })}
                                        />
                                        <p className="text-xs text-muted-foreground">Required for custom dishes.</p>
                                    </div>
                                    <div className="pt-4 flex gap-2">
                                        <Button type="button" variant="outline" onClick={() => setSearchQuery('')}>Cancel</Button>
                                        <Button type="submit" disabled={uploading}>{uploading ? 'Creating...' : 'Create & Select'}</Button>
                                    </div>
                                </form>
                            </CardContent>
                        </Card>
                    ) : catalog.length === 0 ? (
                        <div className="flex flex-col items-center justify-center p-12 text-center border-2 border-dashed rounded-xl bg-gray-50/50">
                            <span className="text-4xl mb-4">🍽️</span>
                            <h3 className="text-lg font-medium">No dishes found</h3>
                            <p className="text-muted-foreground mb-6">There are no dishes matching your current filters.</p>
                            <Button variant="outline" onClick={() => { setSearchQuery(''); setFilterCategory('All'); setFilterVegType('all'); }}>
                                Clear Filters
                            </Button>
                        </div>
                    ) : (
                        <>
                            <div className="grid grid-cols-2 md:grid-cols-3 gap-6">
                                {catalog.map(item => {
                                    // Check if selected
                                    const selectedItem = selectedDishes.find(d => d._id === item._id)
                                    const isSelected = !!selectedItem
                                    const qty = selectedItem?.maxQuantity || 0

                                    return (
                                        <div
                                            key={item._id}
                                            className={`group relative rounded-2xl overflow-hidden border transition-all duration-300 bg-white dark:bg-zinc-900 shadow-sm
                                                ${isSelected
                                                    ? 'ring-2 ring-primary border-primary shadow-lg scale-[1.02]'
                                                    : 'border-gray-200 hover:shadow-md hover:border-gray-300'
                                                }
                                            `}
                                        >
                                            {/* Image & Overlay Section */}
                                            <div
                                                className="aspect-[4/3] relative cursor-pointer overflow-hidden"
                                                onClick={() => !isSelected && toggleDishSelection(item)}
                                            >
                                                <img
                                                    src={item.imageUrl}
                                                    alt={item.foodName}
                                                    className={`w-full h-full object-cover transition-all duration-300 
                                                        ${isSelected ? 'blur-sm scale-110 opacity-40' : 'group-hover:scale-105'}
                                                    `}
                                                    loading="lazy"
                                                />

                                                {/* SELECTION OVERLAY WITH QUANTITY CONTROLS */}
                                                {/* Shows when selected OR on hover (optionally) */}
                                                <div className={`absolute inset-0 flex flex-col items-center justify-center transition-all duration-200
                                                    ${isSelected ? 'opacity-100 bg-black/60 backdrop-blur-[2px]' : 'opacity-0 group-hover:opacity-100 bg-black/30'}
                                                `}>
                                                    {isSelected ? (
                                                        <div className="flex items-center gap-3 bg-white dark:bg-zinc-800 p-2 rounded-full shadow-2xl animate-in fade-in zoom-in-50 duration-200 transform scale-110">
                                                            <Button
                                                                variant="ghost"
                                                                size="icon"
                                                                className="h-8 w-8 rounded-full hover:bg-red-50 hover:text-red-500 text-gray-800 dark:text-gray-200 font-bold"
                                                                onClick={(e) => {
                                                                    e.stopPropagation();
                                                                    if (qty <= 1) {
                                                                        toggleDishSelection(item); // Remove if going to 0
                                                                    } else {
                                                                        if (selectedItem?.uiId) updateMaxQuantity(selectedItem.uiId, -1);
                                                                    }
                                                                }}
                                                            >
                                                                <span className="text-xl font-bold leading-none mb-1">-</span>
                                                            </Button>

                                                            <div className="flex flex-col items-center min-w-[2.5rem]">
                                                                <span className="text-xl font-extrabold tabular-nums text-primary leading-none shadow-sm">{qty}</span>
                                                                <span className="text-[8px] text-muted-foreground font-black uppercase tracking-widest mt-0.5">LIMIT</span>
                                                            </div>

                                                            <Button
                                                                variant="ghost"
                                                                size="icon"
                                                                className="h-8 w-8 rounded-full hover:bg-green-50 hover:text-green-600 text-gray-800 dark:text-gray-200 font-bold"
                                                                onClick={(e) => {
                                                                    e.stopPropagation();
                                                                    if (selectedItem?.uiId) updateMaxQuantity(selectedItem.uiId, 1);
                                                                }}
                                                            >
                                                                <span className="text-xl font-bold leading-none mb-1">+</span>
                                                            </Button>
                                                        </div>
                                                    ) : (
                                                        <div className="bg-white/95 text-primary dark:bg-zinc-800/95 backdrop-blur-md px-5 py-2.5 rounded-full font-bold text-sm shadow-xl transform translate-y-4 group-hover:translate-y-0 transition-all duration-300">
                                                            Click to Add
                                                        </div>
                                                    )}
                                                </div>

                                                {/* Checkbox Indicator (Top Right) */}
                                                <div className={`absolute top-3 right-3 w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all duration-300 z-10
                                                    ${isSelected
                                                        ? 'bg-primary border-primary text-white scale-110'
                                                        : 'bg-white/50 border-white/70 text-transparent'
                                                    }
                                                `}>
                                                    <Check className="w-3.5 h-3.5 stroke-[4]" />
                                                </div>

                                                {/* Veg/Non-Veg Badge (Bottom Left) */}
                                                <Badge variant="secondary" className={`absolute bottom-3 left-3 text-[10px] px-2 py-0.5 backdrop-blur-md bg-white/90 font-bold border-0 shadow-sm
                                                    ${item.vegOrNonVeg === 'veg' ? 'text-green-700' : 'text-red-700'}
                                                `}>
                                                    {item.vegOrNonVeg === 'veg' ? 'VEG' : 'NON-VEG'}
                                                </Badge>
                                            </div>

                                            {/* Details Section */}
                                            <div className="p-4 bg-white dark:bg-zinc-900 border-t border-gray-100 dark:border-zinc-800">
                                                <div className="flex justify-between items-start">
                                                    <div>
                                                        <h3 className={`font-bold text-sm truncate pr-2 transition-colors ${isSelected ? 'text-primary' : 'text-foreground'}`} title={item.foodName}>
                                                            {item.foodName}
                                                        </h3>
                                                        <p className="text-xs text-muted-foreground mt-0.5">{item.category}</p>
                                                    </div>
                                                </div>
                                            </div>
                                        </div>
                                    )
                                })}
                            </div>

                            {/* LOAD MORE BUTTON */}
                            {hasMore && catalog.length > 0 && (
                                <div className="flex justify-center pt-8">
                                    <Button
                                        variant="outline"
                                        size="lg"
                                        onClick={() => fetchDishes(false)}
                                        disabled={loadingMore}
                                        className="w-full md:w-auto px-8 py-6 rounded-xl border-dashed border-2 hover:border-primary/50 hover:bg-primary/5 hover:text-primary transition-all"
                                    >
                                        {loadingMore ? 'Loading More Dishes...' : 'Load More Dishes'}
                                    </Button>
                                </div>
                            )}

                            {!hasMore && catalog.length > 0 && (
                                <div className="text-center py-8 opacity-50">
                                    <p className="text-sm">You have reached the end of the menu.</p>
                                </div>
                            )}
                        </>
                    )}
                </div>
            </div>
        </div>
    )
}

"use client"

import { useState, useEffect } from 'react'
import { useParams, useRouter, useSearchParams } from 'next/navigation'
import { Button } from "@/components/ui/button"
import { Card, CardContent } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { ArrowLeft, Check, Minus, Plus, ShoppingBag, Info, AlertCircle, Loader2 } from "lucide-react"
import { toast } from "sonner"
import { cn } from "@/lib/utils"

interface FoodItem {
    _id: string
    foodName: string
    imageUrl: string
    category: string
    vegOrNonVeg: 'veg' | 'non-veg'
    price: number
    mealType: string
}

interface SelectionState {
    [dishId: string]: {
        dishName: string
        quantity: number
        imageUrl: string
        vegOrNonVeg: 'veg' | 'non-veg'
    }
}

export default function MealSelectionPage() {
    const params = useParams()
    const searchParams = useSearchParams()
    const router = useRouter()

    const dateStr = params.date as string
    const mealType = params.mealType as string
    const preferredDiet = searchParams.get('diet') // 'veg' or 'non-veg'

    const [items, setItems] = useState<FoodItem[]>([])
    // Strict Independent State
    const [selections, setSelections] = useState<SelectionState>({})
    const [loading, setLoading] = useState(true)
    const [submitting, setSubmitting] = useState(false)
    const [timeError, setTimeError] = useState<string | null>(null)
    const [maxDishesAllowed, setMaxDishesAllowed] = useState<number | null>(null);

    // REMOVED: Global Dish Limit (MAX_DISHES)
    // REMOVED: Hardcoded MAX_PLATES_PER_DISH

    // Time Validation Helper
    const checkTimeWindow = (): string | null => {
        const now = new Date();
        const year = now.getFullYear();
        const month = String(now.getMonth() + 1).padStart(2, '0');
        const day = String(now.getDate()).padStart(2, '0');
        const todayStr = `${year}-${month}-${day}`;

        // Only enforce for today
        if (dateStr !== todayStr) return null;

        const minutes = now.getHours() * 60 + now.getMinutes();

        // Breakfast: Until 8:00 AM (480)
        // Lunch: Until 1:00 PM (780)
        // Dinner: Until 8:00 PM (1200)

        switch (mealType.toLowerCase()) {
            case 'breakfast':
                if (minutes >= 480) return "Breakfast booking closed at 8:00 AM";
                break;
            case 'lunch':
                if (minutes >= 780) return "Lunch booking closed at 1:00 PM";
                break;
            case 'dinner':
                if (minutes >= 1200) return "Dinner booking closed at 8:00 PM";
                break;
        }
        return null;
    }

    useEffect(() => {
        // Initial Time Check
        const error = checkTimeWindow();
        if (error) {
            setTimeError(error);
            setLoading(false);
            return;
        }

        const fetchData = async () => {
            try {
                const token = localStorage.getItem('token')

                // 1. Fetch Menu
                const menuRes = await fetch(`/api/student/today-menu?date=${dateStr}`, {
                    headers: { 'Authorization': `Bearer ${token}` }
                });
                const menuData = await menuRes.json();

                const lowerMealType = mealType.toLowerCase();
                let mealItems = menuData[lowerMealType] || [];

                // Load Configured Limit
                const limit = menuData[`${lowerMealType}MaxDishes`];
                if (limit !== undefined && limit !== null) {
                    setMaxDishesAllowed(limit);
                } else {
                    setMaxDishesAllowed(null); // No limit
                }

                if (preferredDiet) {
                    mealItems = mealItems.sort((a: any, b: any) =>
                        a.vegOrNonVeg === preferredDiet ? -1 : 1
                    );
                }
                setItems(mealItems);

            } catch (error) {
                console.error("Failed to load data", error);
                toast.error("Failed to load menu items");
            } finally {
                setLoading(false);
            }
        };

        if (dateStr && mealType) {
            fetchData();
        }
    }, [dateStr, mealType, preferredDiet]);

    const handleAdd = (item: FoodItem & { maxQuantity?: number }) => {

        setSelections(prev => {
            const currentTotal = Object.keys(prev).length;

            // Check Global Limit (Configurable)
            // If item is already selected, we are just increasing quantity, so dish count doesn't increase.
            // If item is NEW (not in prev), check if we hit the limit.
            if (!prev[item._id] && maxDishesAllowed !== null && currentTotal >= maxDishesAllowed) {
                toast.warning(`You can select up to ${maxDishesAllowed} different dishes for this meal.`);
                return prev;
            }

            const current = prev[item._id]?.quantity || 0;
            const maxAllowed = item.maxQuantity || 1; // Default to 1 if not set

            if (current >= maxAllowed) {
                toast.warning(`Max ${maxAllowed} plates allowed for this item.`);
                return prev;
            }

            return {
                ...prev,
                [item._id]: {
                    dishName: item.foodName,
                    quantity: current + 1,
                    imageUrl: item.imageUrl,
                    vegOrNonVeg: item.vegOrNonVeg
                }
            };
        });
    };

    const handleRemove = (dishId: string) => {
        setSelections(prev => {
            const current = prev[dishId]?.quantity || 0;
            if (current <= 1) {
                // Remove completely
                const next = { ...prev };
                delete next[dishId];
                return next;
            }
            return {
                ...prev,
                [dishId]: { ...prev[dishId], quantity: current - 1 }
            };
        });
    };

    const handleConfirm = async () => {
        if (Object.keys(selections).length === 0) {
            toast.error("Please select at least one item");
            return;
        }

        setSubmitting(true);
        try {
            const token = localStorage.getItem('token');

            // Construct strictly typed payload
            const payload: any = {
                date: dateStr
            };

            payload[mealType.toLowerCase()] = {
                status: 'opt-in',
                selectedItems: Object.entries(selections).map(([id, val]) => ({
                    dishId: id,
                    dishName: val.dishName,
                    quantity: val.quantity
                }))
            };

            const res = await fetch('/api/student/select', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`
                },
                body: JSON.stringify(payload)
            });


            const result = await res.json();

            if (!res.ok) {
                toast.error(result.msg || "Selection failed");
                return;
            }

            toast.success("Confirmed! Enjoy your meal.");
            router.push('/student/menu');

        } catch (error) {
            console.error("Submission error", error);
            toast.error("Failed to submit selection");
        } finally {
            setSubmitting(false);
        }
    };

    if (loading) {
        return (
            <div className="min-h-screen flex items-center justify-center bg-[#F4F5F7] dark:bg-zinc-950">
                <Loader2 className="h-8 w-8 animate-spin text-primary" />
            </div>
        );
    }

    // CHANGED: Instead of full page error, we just disable controls
    const isReadOnly = !!timeError;

    const totalSelectedDishes = Object.keys(selections).length;

    // ... (keep fetch logic) ...

    return (
        <div className="min-h-screen bg-slate-50 dark:bg-zinc-950 pb-32">
            {/* Header */}
            <div className="sticky top-0 z-30 bg-white/80 dark:bg-zinc-950/80 backdrop-blur-md border-b border-gray-200 dark:border-zinc-800">
                <div className="container max-w-lg mx-auto px-4 h-16 flex items-center justify-between">
                    <Button variant="ghost" size="icon" onClick={() => router.back()} className="-ml-2">
                        <ArrowLeft className="h-5 w-5" />
                    </Button>
                    <div className="flex flex-col items-center">
                        <div className="font-semibold capitalize text-lg">{mealType} Selection</div>
                        {/* Last Updated Display */}
                        {items.length > 0 && (items[0] as any).updatedAt && (
                            <span className="text-[10px] text-muted-foreground">
                                Updated: {new Date((items[0] as any).updatedAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                            </span>
                        )}
                    </div>
                    <div className="w-9" />
                </div>
            </div>

            <div className="container max-w-lg mx-auto px-4 py-6 space-y-6">

                {/* READ ONLY BANNER */}
                {isReadOnly && (
                    <div className="bg-orange-50 dark:bg-orange-900/20 text-orange-800 dark:text-orange-200 p-4 rounded-xl flex gap-3 text-sm border border-orange-100 dark:border-orange-900 animate-in slide-in-from-top-2">
                        <AlertCircle className="h-5 w-5 shrink-0" />
                        <div>
                            <p className="font-bold mb-0.5">Booking is Closed</p>
                            <p className="opacity-90">{timeError} - Menu is now final.</p>
                        </div>
                    </div>
                )}

                {/* Info Card (Hide if Read Only to reduce clutter, or keep? Keep for policy info) */}
                {!isReadOnly && (
                    <div className="bg-blue-50 dark:bg-blue-900/20 text-blue-800 dark:text-blue-200 p-4 rounded-xl flex gap-3 text-sm border border-blue-100 dark:border-blue-900">
                        <Info className="h-5 w-5 shrink-0" />
                        <div>
                            <p className="font-semibold mb-1">Ordering Policy:</p>
                            <ul className="list-disc list-inside space-y-0.5 opacity-90">
                                <li>
                                    {maxDishesAllowed !== null
                                        ? <span>Select up to <strong>{maxDishesAllowed} dish types</strong></span>
                                        : <span>Select <strong>any number of dishes</strong></span>
                                    }
                                </li>
                                <li>Quantity limits apply <strong>per item</strong></li>
                            </ul>
                        </div>
                    </div>
                )}

                {/* Items Grid */}
                {items.length === 0 ? (
                    <div className="text-center py-12 text-muted-foreground">
                        <ShoppingBag className="h-12 w-12 mx-auto mb-4 opacity-20" />
                        <p>No items found for this meal.</p>
                    </div>
                ) : (
                    <div className="space-y-4">
                        {items.map((item) => {
                            const selection = selections[item._id];
                            const qty = selection?.quantity || 0;
                            const isSelected = qty > 0;

                            // Disable Add if:
                            // 1. Max plates reached for this dish
                            const maxAllowed = (item as any).maxQuantity || 1;
                            const isPlateLimitReached = qty >= maxAllowed;

                            return (
                                <Card key={item._id} className={cn("overflow-hidden border-0 shadow-sm transition-all duration-200", isSelected ? "ring-2 ring-primary bg-primary/5" : "bg-white dark:bg-zinc-900")}>
                                    <div className="flex p-3 gap-4">
                                        <div className="h-24 w-24 shrink-0 rounded-lg overflow-hidden bg-gray-100 relative">
                                            {item.imageUrl ? (
                                                <img src={item.imageUrl} alt={item.foodName} className="h-full w-full object-cover" />
                                            ) : (
                                                <div className="h-full w-full flex items-center justify-center text-xs text-muted-foreground">Img</div>
                                            )}
                                        </div>
                                        <div className="flex-1 flex flex-col justify-between py-1">
                                            <div>
                                                <div className="flex justify-between items-start">
                                                    <h3 className="font-semibold text-gray-900 dark:text-gray-100 line-clamp-1">{item.foodName}</h3>
                                                    <div className={cn(
                                                        "px-2 py-0.5 rounded text-[10px] font-bold border uppercase tracking-wider",
                                                        item.vegOrNonVeg === 'veg'
                                                            ? "bg-green-50 text-green-700 border-green-200 dark:bg-green-900/20 dark:text-green-400 dark:border-green-800"
                                                            : "bg-red-50 text-red-700 border-red-200 dark:bg-red-900/20 dark:text-red-400 dark:border-red-800"
                                                    )}>
                                                        {item.vegOrNonVeg === 'veg' ? 'Veg' : 'Non-Veg'}
                                                    </div>
                                                </div>
                                                <p className="text-xs text-muted-foreground mt-1 capitalize">{item.category}</p>
                                                <p className="text-[10px] text-muted-foreground mt-0.5">Max allowed: {maxAllowed}</p>
                                            </div>

                                            <div className="flex items-center justify-between mt-3">
                                                {isSelected ? (
                                                    <div className="flex items-center gap-3 bg-white dark:bg-zinc-800 rounded-lg p-1 shadow-sm border">
                                                        <Button
                                                            variant="ghost"
                                                            size="icon"
                                                            className="h-7 w-7 rounded-md hover:bg-slate-100 text-red-500"
                                                            disabled={isReadOnly}
                                                            onClick={() => handleRemove(item._id)}
                                                        >
                                                            <Minus className="h-3 w-3" />
                                                        </Button>
                                                        <span className="font-bold text-sm min-w-[1.5rem] text-center tabular-nums">{qty}</span>
                                                        <Button
                                                            variant="ghost"
                                                            size="icon"
                                                            className="h-7 w-7 rounded-md hover:bg-slate-100 text-green-600"
                                                            disabled={isPlateLimitReached || isReadOnly}
                                                            onClick={() => handleAdd(item)}
                                                        >
                                                            <Plus className="h-3 w-3" />
                                                        </Button>
                                                    </div>
                                                ) : (
                                                    <Button
                                                        size="sm"
                                                        className="h-8 px-5 font-semibold"
                                                        disabled={isReadOnly}
                                                        onClick={() => handleAdd(item)}
                                                    >
                                                        {isReadOnly ? 'Closed' : 'Add'}
                                                    </Button>
                                                )}
                                            </div>
                                        </div>
                                    </div>
                                </Card>
                            );
                        })}
                    </div>
                )}
            </div>

            {/* Bottom Bar */}
            <div className="fixed bottom-0 left-0 right-0 p-4 bg-white/95 dark:bg-zinc-950/95 backdrop-blur border-t border-gray-200 dark:border-zinc-800 z-30 shadow-[0_-5px_15px_-5px_rgba(0,0,0,0.1)]">
                <div className="container max-w-lg mx-auto flex items-center justify-between gap-4">
                    <div className="flex flex-col">
                        <span className="text-xs text-muted-foreground font-medium uppercase tracking-wider">Selected</span>
                        <div className="font-bold text-xl flex items-center gap-1">
                            {totalSelectedDishes} <span className="text-sm font-normal text-muted-foreground">Dishes</span>
                        </div>
                    </div>
                    <Button
                        size="lg"
                        className="px-8 font-bold rounded-xl shadow-lg shadow-primary/25"
                        onClick={handleConfirm}
                        disabled={totalSelectedDishes === 0 || submitting}
                    >
                        {submitting ? <Loader2 className="animate-spin h-5 w-5 mr-2" /> : <Check className="w-5 h-5 mr-2" />}
                        Confirm
                    </Button>
                </div>
            </div>
        </div>
    )
}

"use client"

import { useState, useEffect } from 'react'
import { Card, CardContent } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs"
import { Badge } from "@/components/ui/badge"
import { Utensils, ShoppingBag, Leaf, Flame, Moon, ArrowRight, ChevronRight, Info, CalendarDays } from "lucide-react"
import { toast } from "sonner"
import { useRouter } from 'next/navigation'
import { cn } from "@/lib/utils"

interface FoodItem {
    _id: string
    foodName: string
    imageUrl: string
    mealType: string
    price: number
    category: string
    vegOrNonVeg: 'veg' | 'non-veg'
}

interface Menu {
    _id: string
    date: string
    breakfast: FoodItem[]
    lunch: FoodItem[]
    dinner: FoodItem[]
    breakfastStatus?: string
    lunchStatus?: string
    dinnerStatus?: string
}

export default function StudentMenuPage() {
    const [menus, setMenus] = useState<Menu[]>([])
    const [loading, setLoading] = useState(true)
    const [error, setError] = useState<string | null>(null)
    const router = useRouter()

    const days = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"]

    useEffect(() => {
        const cached = localStorage.getItem('student_menu_cache')
        if (cached) {
            try {
                const parsed = JSON.parse(cached)
                if (Array.isArray(parsed)) {
                    setMenus(parsed)
                    setLoading(false) // Show cached data immediately
                }
            } catch (e) {
                console.error("Cache parse error", e)
            }
        }
        fetchMenus()
    }, [])

    // State for UX enhancements
    const [isRefreshing, setIsRefreshing] = useState(false);
    const [lastChecked, setLastChecked] = useState<Date | null>(null);

    const handleRefresh = async () => {
        if (isRefreshing) return;

        setIsRefreshing(true);
        // Minimum delay to show the loading state (UX)
        const minDelay = new Promise(resolve => setTimeout(resolve, 800));

        await Promise.all([fetchMenus(true), minDelay]);

        setLastChecked(new Date());
        setIsRefreshing(false);
        toast.success("Menu updated");
    };

    const fetchMenus = async (isBackgroundRefresh = false) => {
        try {
            if (!isBackgroundRefresh) setLoading(true);
            setError(null)
            const token = localStorage.getItem('token')
            if (!token) {
                // Handle missing token gracefully if needed, or rely on API to return 401
            }
            const response = await fetch('/api/student/menu', {
                headers: {
                    'Authorization': `Bearer ${token}`
                }
            })
            if (response.ok) {
                const data = await response.json()
                if (Array.isArray(data)) {
                    setMenus(data)
                    localStorage.setItem('student_menu_cache', JSON.stringify(data))
                } else {
                    console.error("API returned non-array data:", data)
                    setMenus([])
                }
            } else {
                console.error("Failed to fetch menu:", response.status)
                if (response.status !== 404) setError("Failed to load menu")
            }
        } catch (error) {
            console.error('Error fetching menus:', error)
            setError("Connection failed")
            toast.error("Failed to load menu")
        } finally {
            if (!isBackgroundRefresh) setLoading(false)
        }
    }

    const getMealTime = (type: string) => {
        switch (type.toLowerCase()) {
            case 'breakfast': return "7:30 AM - 9:30 AM"
            case 'lunch': return "12:30 PM - 2:30 PM"
            case 'dinner': return "7:30 PM - 9:30 PM"
            default: return ""
        }
    }

    const MealSummaryCard = ({ menu, mealType, icon: Icon, colorClass, gradientClass, title, dateStr }: {
        menu: Menu,
        mealType: 'breakfast' | 'lunch' | 'dinner',
        icon: any,
        colorClass: string,
        gradientClass: string,
        title: string,
        dateStr: string
    }) => {
        // Helper to check availability
        // Now strictly enforces status === 'PUBLISHED'
        const isMenuAvailable = (items: any[], status: string) => {
            if (!items || items.length === 0) return false;
            if (status === 'DRAFT') return false;
            return true;
        };

        const statusKey = `${mealType}Status` as keyof Menu;
        // @ts-ignore - status fields are dynamically added by API
        const status = menu[statusKey] as string;

        const hasItems = isMenuAvailable(menu[mealType], status);
        const items = hasItems ? menu[mealType] : [];

        // --- EMPTY STATE LOGIC START ---
        const getEmptyStateContent = () => {
            const now = new Date();
            const menuDate = new Date(dateStr);

            // Normalize dates for comparison (reset time)
            const today = new Date();
            today.setHours(0, 0, 0, 0);

            const menuDay = new Date(menuDate);
            menuDay.setHours(0, 0, 0, 0); // Assuming menu.date is already normalized YYYY-MM-DD but forcing midnight just in case

            // 1. Past Date -> Always "Ended"
            if (menuDay < today) {
                return {
                    title: "Menu Not Available",
                    message: "This date has passed.",
                    icon: Utensils
                };
            }

            // 2. Future Date -> Always "Coming Soon"
            if (menuDay > today) {
                return {
                    title: "Not Yet Updated",
                    message: "Menu not published yet.",
                    icon: CalendarDays // Using CalendarDays for future empty state
                };
            }

            // 3. Today -> Check Time Windows
            const currentMinutes = now.getHours() * 60 + now.getMinutes();

            // Booking Cutoff Times (minutes from midnight)
            const END_TIMES = {
                breakfast: 8 * 60,      // 8:00 AM = 480
                lunch: 13 * 60,         // 1:00 PM = 780
                dinner: 20 * 60         // 8:00 PM = 1200
            };

            const endTime = END_TIMES[mealType];

            if (currentMinutes > endTime) {
                return {
                    title: "Meal Time Ended",
                    message: "This menu is no longer available.",
                    icon: Moon // Or a Clock/X icon?
                };
            } else {
                return {
                    title: "Menu Not Available Yet",
                    message: "This meal will be updated by the hostel shortly.",
                    icon: Utensils // Hourglass?
                };
            }
        };

        const emptyState = getEmptyStateContent();
        // --- EMPTY STATE LOGIC END ---

        return (
            <div className={cn(
                "group relative overflow-hidden rounded-3xl bg-white dark:bg-zinc-900 border border-gray-100 dark:border-zinc-800 shadow-sm transition-all duration-300",
                hasItems ? "hover:shadow-xl" : "opacity-90"
            )}>
                {hasItems && (
                    <div className={`absolute inset-0 opacity-0 group-hover:opacity-5 transition-opacity duration-500 ${gradientClass}`} />
                )}

                <div className="p-6 relative z-10">
                    <div className="flex justify-between items-start mb-6">
                        <div className="flex items-center gap-3">
                            <div className={cn(
                                "p-3 rounded-2xl bg-opacity-10 dark:bg-opacity-20",
                                hasItems ? colorClass : "bg-gray-100 dark:bg-zinc-800"
                            )}>
                                <Icon className={cn(
                                    "w-6 h-6",
                                    hasItems ? colorClass.replace('bg-', 'text-') : "text-gray-400"
                                )} />
                            </div>
                            <div>
                                <h3 className={cn("text-2xl font-bold", hasItems ? "text-gray-900 dark:text-gray-100" : "text-gray-500 dark:text-gray-500")}>{title}</h3>
                                <p className="text-sm font-medium text-muted-foreground flex items-center gap-1.5 mt-1">
                                    <span className={cn("w-1.5 h-1.5 rounded-full", hasItems ? "bg-gray-300 dark:bg-zinc-700" : "bg-gray-200")} />
                                    {getMealTime(mealType)}
                                </p>
                            </div>
                        </div>
                    </div>

                    {!hasItems ? (
                        <div className="py-8 flex flex-col items-center justify-center text-center space-y-3">
                            <div className="w-12 h-12 rounded-full bg-gray-50 dark:bg-zinc-800/50 flex items-center justify-center">
                                {/* Dynamic Icon based on state */}
                                <emptyState.icon className="w-5 h-5 text-gray-300 dark:text-zinc-600" />
                            </div>
                            <h4 className="text-sm font-semibold text-gray-700 dark:text-gray-300">{emptyState.title}</h4>
                            <p className="text-xs text-muted-foreground/70 max-w-[200px]">{emptyState.message}</p>
                        </div>
                    ) : (
                        <>
                            <div className="space-y-4 mb-8">
                                {items.slice(0, 3).map((item, idx) => (
                                    <div key={idx} className="flex items-center gap-3 group/item">
                                        <div className="h-12 w-12 rounded-lg overflow-hidden bg-gray-100 dark:bg-zinc-800 flex-shrink-0 border border-gray-100 dark:border-zinc-700">
                                            {item.imageUrl ? (
                                                <img src={item.imageUrl} alt={item.foodName} className="h-full w-full object-cover" />
                                            ) : (
                                                <div className="h-full w-full flex items-center justify-center text-xs text-muted-foreground">Img</div>
                                            )}
                                        </div>
                                        <div className="min-w-0 flex-1">
                                            <div className="flex items-center gap-2 mb-0.5">
                                                <div className={`w-1.5 h-1.5 rounded-full flex-shrink-0 ${item.vegOrNonVeg === 'veg' ? 'bg-green-500' : 'bg-red-500'}`} />
                                                <span className="text-sm font-semibold text-gray-700 dark:text-gray-200 truncate group-hover/item:text-primary transition-colors">{item.foodName}</span>
                                            </div>
                                            <p className="text-[10px] text-muted-foreground line-clamp-1">{item.category}</p>
                                        </div>
                                    </div>
                                ))}
                                {items.length > 3 && (
                                    <div className="pl-15 pt-1">
                                        <p className="text-xs text-muted-foreground font-medium hover:text-primary cursor-pointer transition-colors">+ {items.length - 3} more items...</p>
                                    </div>
                                )}
                            </div>

                            <div className="grid grid-cols-2 gap-3">
                                <Button
                                    className="w-full bg-green-50 text-green-700 hover:bg-green-100 dark:bg-green-900/20 dark:text-green-300 border border-green-200 dark:border-green-800 font-bold h-11"
                                    onClick={() => router.push(`/student/menu/${dateStr}/${mealType}?diet=veg`)}
                                >
                                    <Leaf className="w-4 h-4 mr-2" />
                                    Veg
                                </Button>
                                <Button
                                    className="w-full bg-red-50 text-red-700 hover:bg-red-100 dark:bg-red-900/20 dark:text-red-300 border border-red-200 dark:border-red-800 font-bold h-11"
                                    onClick={() => router.push(`/student/menu/${dateStr}/${mealType}?diet=non-veg`)}
                                >
                                    <Flame className="w-4 h-4 mr-2" />
                                    Non-Veg
                                </Button>
                            </div>
                        </>
                    )}
                </div>
            </div>
        )
    }

    if (loading && menus.length === 0) {
        return (
            <div className="container mx-auto p-4 md:p-8 max-w-7xl animate-pulse space-y-8">
                <div className="h-10 w-48 bg-gray-200 rounded-lg" />
                <div className="flex gap-4 overflow-hidden py-2">
                    {[1, 2, 3, 4, 5].map(i => <div key={i} className="h-20 w-16 bg-gray-200 rounded-2xl flex-shrink-0" />)}
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {[1, 2, 3].map(i => <div key={i} className="h-80 bg-gray-200 rounded-2xl" />)}
                </div>
            </div>
        )
    }

    if (error && menus.length === 0) {
        return (
            <div className="min-h-screen flex flex-col items-center justify-center space-y-4">
                <div className="text-red-500 font-bold text-lg">{error}</div>
                <Button onClick={() => fetchMenus()} variant="outline">Retry</Button>
            </div>
        )
    }

    // Process dates safely
    const menusByDate = new Map<string, Menu>()
    if (Array.isArray(menus)) {
        menus.forEach(menu => {
            try {
                if (menu.date) {
                    const date = new Date(menu.date).toISOString().split('T')[0]
                    menusByDate.set(date, menu)
                }
            } catch (e) {
                console.error("Error processing menu date:", menu, e)
            }
        })
    }

    // Generate dates for the next 7 days
    const weekDays = Array.from({ length: 7 }, (_, i) => {
        const date = new Date();
        date.setDate(date.getDate() + i);

        const year = date.getFullYear();
        const month = String(date.getMonth() + 1).padStart(2, '0');
        const day = String(date.getDate()).padStart(2, '0');
        const localDateStr = `${year}-${month}-${day}`;

        return {
            label: date.toLocaleDateString('en-US', { weekday: 'short' }),
            fullLabel: date.toLocaleDateString('en-US', { weekday: 'long' }),
            dateStr: date.toLocaleDateString('en-US', { day: 'numeric', month: 'short' }),
            dateValue: localDateStr,
            dayNum: date.getDate(),
        };
    });

    return (
        <div className="min-h-screen bg-slate-50 dark:bg-zinc-950 pb-24 font-sans selection:bg-primary/20">
            {/* Header */}
            <div className="sticky top-0 z-40 bg-white/80 dark:bg-zinc-950/80 backdrop-blur-xl border-b border-gray-200/50 supports-[backdrop-filter]:bg-white/60">
                <div className="container mx-auto px-4 py-4 max-w-7xl flex justify-between items-center">
                    <div className="flex items-center gap-3">
                        <div className="bg-gradient-to-br from-emerald-500 to-emerald-700 p-2.5 rounded-xl text-white shadow-lg shadow-emerald-500/20">
                            <Utensils className="w-5 h-5" />
                        </div>
                        <div>
                            <h1 className="text-xl font-bold text-gray-900 dark:text-gray-100 tracking-tight leading-none">Hostel Menu</h1>
                            <p className="text-xs text-muted-foreground font-medium mt-1">Plan your meals for the week</p>
                        </div>
                    </div>
                </div>
            </div>

            {/* Date Tabs */}
            <div className="container mx-auto px-4 mt-8 max-w-7xl">
                <Tabs defaultValue={weekDays[0].dateValue} className="space-y-8">
                    {/* Desktop: Grid / Mobile: Scrollable Flex */}
                    <div className="relative">
                        <TabsList className="w-full h-auto bg-transparent p-0 gap-3 md:gap-4 overflow-x-auto flex md:grid md:grid-cols-7 no-scrollbar pb-4 snap-x snap-mandatory">
                            {weekDays.map(day => (
                                <TabsTrigger
                                    key={day.dateValue}
                                    value={day.dateValue}
                                    className="group snap-center flex-col items-center justify-center h-20 md:h-24 min-w-[4.5rem] rounded-2xl border bg-white dark:bg-zinc-900 border-gray-200 dark:border-zinc-800 data-[state=active]:bg-primary data-[state=active]:text-primary-foreground data-[state=active]:border-primary transition-all duration-300 shadow-sm hover:border-primary/50 hover:shadow-md data-[state=active]:shadow-blue-500/25 data-[state=active]:scale-[1.02] cursor-pointer"
                                    title={`View menu for ${day.fullLabel}`}
                                >
                                    <span className="text-[11px] font-bold uppercase tracking-wider opacity-60 mb-1 group-data-[state=active]:opacity-90">{day.label}</span>
                                    <span className="text-2xl font-extrabold tracking-tight group-data-[state=active]:text-white">{day.dayNum}</span>
                                </TabsTrigger>
                            ))}
                        </TabsList>
                        {/* Mobile Scroll Hint (Optional - visible only on mobile if content overflows) */}
                        <div className="md:hidden absolute right-0 top-0 bottom-4 w-8 bg-gradient-to-l from-[#F4F5F7] to-transparent pointer-events-none dark:from-zinc-950" />
                    </div>

                    {weekDays.map(day => {
                        const menu = menusByDate.get(day.dateValue)
                        const isMealPublished = (items: any[], status: any) => {
                            return (items && items.length > 0) && (status !== 'DRAFT');
                        };

                        const hasMenu = menu && (
                            isMealPublished(menu.breakfast, menu.breakfastStatus) ||
                            isMealPublished(menu.lunch, menu.lunchStatus) ||
                            isMealPublished(menu.dinner, menu.dinnerStatus)
                        )

                        return (
                            <TabsContent key={day.dateValue} value={day.dateValue} className="animate-in fade-in-50 slide-in-from-bottom-4 duration-500 focus-visible:outline-none min-h-[50vh]">
                                {loading ? (
                                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6 animate-pulse">
                                        {[1, 2, 3].map(i => <div key={i} className="h-96 bg-gray-200 dark:bg-zinc-800 rounded-3xl" />)}
                                    </div>
                                ) : hasMenu && menu ? (
                                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                                        <MealSummaryCard
                                            menu={menu}
                                            mealType="breakfast"
                                            title="Breakfast"
                                            icon={Leaf}
                                            colorClass="bg-green-500"
                                            gradientClass="bg-gradient-to-br from-green-500 via-emerald-500 to-teal-500"
                                            dateStr={day.dateValue}
                                        />
                                        <MealSummaryCard
                                            menu={menu}
                                            mealType="lunch"
                                            title="Lunch"
                                            icon={Flame}
                                            colorClass="bg-orange-500"
                                            gradientClass="bg-gradient-to-br from-orange-500 via-red-500 to-pink-500"
                                            dateStr={day.dateValue}
                                        />
                                        <MealSummaryCard
                                            menu={menu}
                                            mealType="dinner"
                                            title="Dinner"
                                            icon={Moon}
                                            colorClass="bg-indigo-500"
                                            gradientClass="bg-gradient-to-br from-indigo-500 via-purple-500 to-violet-500"
                                            dateStr={day.dateValue}
                                        />
                                    </div>
                                ) : (
                                    <div className="flex flex-col items-center justify-center py-24 text-center bg-white/50 dark:bg-zinc-900/50 rounded-3xl border border-dashed border-gray-300 dark:border-zinc-700">
                                        <div className="w-20 h-20 bg-gray-100 dark:bg-zinc-800/80 rounded-full flex items-center justify-center mb-6">
                                            <Utensils className="w-8 h-8 text-gray-400" />
                                        </div>
                                        <h3 className="text-xl font-bold text-gray-900 dark:text-gray-100">Menu not updated yet</h3>
                                        <p className="text-muted-foreground mt-2 max-w-sm px-6">
                                            The mess manager hasn't posted the menu for {day.fullLabel} ({day.dateStr}) yet.
                                        </p>
                                        <div className="mt-6 flex flex-col items-center gap-2">
                                            <Button
                                                variant="outline"
                                                onClick={handleRefresh}
                                                disabled={isRefreshing}
                                                className="min-w-[150px]"
                                            >
                                                {isRefreshing ? (
                                                    // Assuming Loader2 is available, or use specific icon
                                                    <div className="h-4 w-4 border-2 border-current border-t-transparent rounded-full animate-spin mr-2" />
                                                ) : "Check for Updates"}
                                                {isRefreshing ? "Checking..." : ""}
                                            </Button>
                                            {lastChecked && (
                                                <span className="text-[10px] text-muted-foreground animate-in fade-in">
                                                    Last checked: {lastChecked.toLocaleTimeString()}
                                                </span>
                                            )}
                                        </div>
                                    </div>
                                )}
                            </TabsContent>
                        )
                    })}
                </Tabs>
            </div>
        </div>
    )
}

"use client"

import {
    Avatar,
    AvatarFallback,
    AvatarImage,
} from "@/components/ui/avatar"
import { Button } from "@/components/ui/button"
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuGroup,
    DropdownMenuItem,
    DropdownMenuLabel,
    DropdownMenuSeparator,
    DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"
import { useRouter } from "next/navigation"
import { useEffect, useState } from "react"
import axios from "axios"
import { API_URL } from "@/lib/config"
import { toast } from "sonner"

interface User {
    name: string;
    email?: string; // Optional if not always available in local
    role: string;
}

export function UserNav() {
    const router = useRouter()
    const [user, setUser] = useState<User | null>(null)

    useEffect(() => {
        // Try to get user from localStorage or cookie-based API
        // Ideally we fetch /api/auth/me but for speed we might check localStorage first if available
        // For now, let's fetch 'me'
        fetchUser()
    }, [])

    const fetchUser = async () => {
        try {
            const res = await axios.get(`${API_URL}/api/auth/me`, { withCredentials: true })
            setUser(res.data)
        } catch (error) {
            // console.error("Failed to fetch user", error)
        }
    }

    const handleLogout = async () => {
        try {
            await axios.post(`${API_URL}/api/auth/logout`, {}, { withCredentials: true })
            localStorage.removeItem('token') // If used
            toast.success("Logged out successfully")
            router.push('/login')
        } catch (error) {
            toast.error("Logout failed")
        }
    }

    if (!user) return null

    // Initials
    const initials = user.name
        ? user.name.split(' ').map(n => n[0]).join('').substring(0, 2).toUpperCase()
        : 'U'

    return (
        <DropdownMenu>
            <DropdownMenuTrigger asChild>
                <Button variant="ghost" className="relative h-8 w-8 rounded-full">
                    <Avatar className="h-9 w-9 border">
                        <AvatarImage src="/avatars/01.png" alt={user.name} />
                        <AvatarFallback className="bg-primary/10 text-primary font-bold">{initials}</AvatarFallback>
                    </Avatar>
                </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent className="w-56" align="end" forceMount>
                <DropdownMenuLabel className="font-normal">
                    <div className="flex flex-col space-y-1">
                        <p className="text-sm font-medium leading-none">{user.name}</p>
                        <p className="text-xs leading-none text-muted-foreground capitalize">
                            {user.role}
                        </p>
                    </div>
                </DropdownMenuLabel>
                <DropdownMenuSeparator />
                <DropdownMenuGroup>
                    <DropdownMenuItem onClick={() => router.push(`/${user.role}/profile`)}>
                        My Profile
                    </DropdownMenuItem>
                </DropdownMenuGroup>
                <DropdownMenuSeparator />
                <DropdownMenuItem onClick={handleLogout} className="text-red-600 focus:text-red-600 focus:bg-red-50">
                    Log out
                </DropdownMenuItem>
            </DropdownMenuContent>
        </DropdownMenu>
    )
}
